import React from "react";
import Link from "next/link";

export default function PostCard({ post }) {
  return (
    <div className="post-card">
      <img
        src={post.image}
        alt={post.title || "Job Image"} // Alt tag empty chorna Next.js build mein kabhi kabhar warning deta hai
      />

      <div className="post-content">
        <h3>{post.title}</h3>

        <p>{post.desc}</p>

        {/* Next.js mein 'to' ki jagah hamesha 'href' use hota hai */}
        <Link href={`/posts/${post.id}`}>
          <button>Read More</button>
        </Link>
      </div>
    </div>
  );
}